class Solution:
    def numberOfGoodPartitions(self, nums):
        MOD = 10 ** 9 + 7
        n = len(nums)
        total = 0
        for mask in range(1 << (n - 1)):
            parts = []
            start = 0
            for i in range(n - 1):
                if (mask >> i) & 1:
                    parts.append(nums[start:i + 1])
                    start = i + 1
            parts.append(nums[start:n])
            seen_overall = set()
            ok = True
            for part in parts:
                s = set(part)
                if seen_overall & s:
                    ok = False
                    break
                seen_overall |= s
            if ok:
                total += 1
        return total % MOD

