class Solution:
    def numberOfGoodPartitions(self, nums):
        MOD = 10 ** 9 + 7
        last = {}
        for i, v in enumerate(nums):
            last[v] = i
        reach = 0
        count = 0
        for i, v in enumerate(nums):
            reach = max(reach, last[v])
            if i == reach:
                count += 1
        return pow(2, count - 1, MOD)

